#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Use sqlgen::insert_or_write to insert records
  // The template parameter T determines the table structure
  // The function automatically handles the SQL generation based on the type
  sqlgen::insert_or_write(conn, records.begin(), records.end()).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Use sqlgen::delete_from with appropriate condition based on table type
  // The condition uses the primary key column with the provided record_id
  // We need to determine the correct primary key column name based on the table
  if (table_name == "Student") {
    // Student table has SNo as primary key (Varchar<10>)
    auto condition = "SNo"_c == record_id;
    (sqlgen::delete_from<Student> | sqlgen::where(condition))(conn).value();
  } else if (table_name == "Course") {
    // Course table has CID as primary key (uint32_t, auto_incr)
    uint32_t id = std::stoul(record_id);
    auto condition = "CID"_c == id;
    (sqlgen::delete_from<Course> | sqlgen::where(condition))(conn).value();
  } else if (table_name == "Score") {
    // Score table has ScID as primary key (uint32_t, auto_incr)
    uint32_t id = std::stoul(record_id);
    auto condition = "ScID"_c == id;
    (sqlgen::delete_from<Score> | sqlgen::where(condition))(conn).value();
  } else if (table_name == "Major") {
    // Major table has MID as primary key (uint32_t)
    uint32_t id = std::stoul(record_id);
    auto condition = "MID"_c == id;
    (sqlgen::delete_from<Major> | sqlgen::where(condition))(conn).value();
  } else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                                const std::string& record_id,
                                const std::string& col_name,
                                const std::string& new_value) {
  // Connect to the database
