    using namespace sqlgen::literals;

    auto query = sqlgen::read<std::vector<ActiveUser>>
        | sqlgen::inner_join<Post, "p">("user_id"_c == "user_id"_c)
        | sqlgen::where("created_at"_c >= "2025-12-01" && "created_at"_c <= "2025-12-31")
        | sqlgen::distinct;

    // 4. Execute the query and return results
    return query(conn).value();
}

}  // namespace query_active_users_posts
