#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_social_network {

struct User {
    sqlgen::PrimaryKey<int> user_id;
    std::string username;
    std::string email;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
    std::string city;
};

struct Friendship {
    int user1_id;
    int user2_id;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
    std::string user1_name;
    std::string user2_name;
};

struct MutualFriendStats {
    std::string username;
    int friend_count;
    double avg_friend_count;
};

struct FriendOfFriend {
    std::string user_name;
    std::string friend_of_friend_name;
};

struct SameCityRecommendation {
    std::string user_name;
    std::string recommended_user_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Create tables using sqlgen's write function
    sqlgen::write(conn, users);
    sqlgen::write(conn, friendships);

    // 1. Find mutual friends using self-join and subquery
    auto mutual_friends_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from<User, "u1">("username"_t1 | sqlgen::as<"user1_name">, 
                                         "username"_t2 | sqlgen::as<"user2_name">)
        | sqlgen::inner_join<Friendship, "f1">("u1"_t1.user_id == "f1"_t2.user_id1)
        | sqlgen::inner_join<Friendship, "f2">("f1"_t2.user_id2 == "f2"_t3.user_id1)
        | sqlgen::inner_join<User, "u2">("f2"_t3.user_id2 == "u2"_t4.user_id)
        | sqlgen::where("u1"_t1.user_id < "u2"_t4.user_id)
        | sqlgen::exists(sqlgen::select_from<Friendship, "f3">()
                           | sqlgen::where("f3"_t5.user_id1 == "u1"_t1.user_id && 
                                       "f3"_t5.user_id2 == "u2"_t4.user_id));

    // 2. Find users with more than average friends using nested query
    auto above_avg_friends_query = sqlgen::read<std::vector<MutualFriendStats>>
        | sqlgen::select_from<User, "u">("username"_t1, 
                                        sqlgen::count("f"_t2.user_id2) | sqlgen::as<"friend_count">)
        | sqlgen::left_join<Friendship, "f">("u"_t1.user_id == "f"_t2.user_id1)
        | sqlgen::group_by("u"_t1.user_id)
        | sqlgen::having(sqlgen::count("f"_t2.user_id2) > 
            (sqlgen::select_from<sqlgen::transpilation::TableWrapper<std::vector<int>>, "avg">()
             | sqlgen::where(sqlgen::avg(sqlgen::count("f"_t2.user_id2)) > 0));

    // 3. Find friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::read<std::vector<FriendOfFriend>>
        | sqlgen::select_from<User, "u">("username"_t1 | sqlgen::as<"user_name">,
                                        "u2"_t4.username | sqlgen::as<"friend_of_friend_name">)
        | sqlgen::inner_join<Friendship, "f1">("u"_t1.user_id == "f1"_t2.user_id1)
        | sqlgen::inner_join<Friendship, "f2">("f1"_t2.user_id2 == "f2"_t3.user_id1)
        | sqlgen::inner_join<User, "u2">("f2"_t3.user_id2 == "u2"_t4.user_id)
        | sqlgen::where("u"_t1.user_id != "u2"_t4.user_id)
        | sqlgen::group_by("u"_t1.user_id, "u2"_t4.user_id)
        | sqlgen::having(sqlgen::count() == 1);

    // 4. Count friends per user and identify most connected users
    auto friend_count_query = sqlgen::read<std::vector<MutualFriendStats>>
        | sqlgen::select_from<User, "u">("username"_t1, 
                                        sqlgen::count("f"_t2.user_id2) | sqlgen::as<"friend_count">)
        | sqlgen::left_join<Friendship, "f">("u"_t1.user_id == "f"_t2.user_id1)
        | sqlgen::group_by("u"_t1.user_id)
        | sqlgen::order_by(sqlgen::count("f"_t2.user_id2).desc());

