        | sqlgen::inner_join<Friendship, "f2">("f1"_t2.user_id2 == "f2"_t3.user_id1)
        | sqlgen::inner_join<User, "u2">("f2"_t3.user_id2 == "u2"_t4.user_id)
        | sqlgen::where("u"_t1.user_id != "u2"_t4.user_id)
        | sqlgen::group_by("u"_t1.user_id, "u2"_t4.user_id)
        | sqlgen::having(sqlgen::count() == 1);

    // 4. Count friends per user and identify most connected users
    auto friend_count_query = sqlgen::read<std::vector<MutualFriendStats>>
        | sqlgen::select_from<User, "u">("username"_t1, 
                                        sqlgen::count("f"_t2.user_id2) | sqlgen::as<"friend_count">)
        | sqlgen::left_join<Friendship, "f">("u"_t1.user_id == "f"_t2.user_id1)
        | sqlgen::group_by("u"_t1.user_id)
        | sqlgen::order_by(sqlgen::count("f"_t2.user_id2).desc());

    // 5. Find users in same city who are not friends (recommendations)
    auto recommendations_query = sqlgen::read<std::vector<SameCityRecommendation>>
        | sqlgen::select_from<User, "u1">("username"_t1 | sqlgen::as<"user_name">,
                                        "u2"_t4.username | sqlgen::as<"recommended_user_name">)
        | sqlgen::inner_join<User, "u2">("u1"_t1.city == "u2"_t4.city && 
                                       "u1"_t1.user_id < "u2"_t4.user_id)
        | sqlgen::where(sqlgen::not_exists(
            sqlgen::select_from<Friendship, "f">()
            | sqlgen::where(("f"_t2.user_id1 == "u1"_t1.user_id && 
                         "f"_t2.user_id2 == "u2"_t4.user_id) || 
                        ("f"_t2.user_id1 == "u2"_t4.user_id && 
                         "f"_t2.user_id2 == "u1"_t1.user_id))
        );

    // Execute all queries
    auto mutual_results = mutual_friends_query(conn).value();
    auto above_avg_results = above_avg_friends_query(conn).value();
    auto friend_of_friend_results = friend_of_friend_query(conn).value();
    auto friend_count_results = friend_count_query(conn).value();
    auto recommendations_results = recommendations_query(conn).value();

    // Return mutual friends results as specified in function signature
    return mutual_results;
}

